题目：
给定个正整数  ，将每个数分解质因数，并按照质因数从小到大的顺序输出每个质因数的底数和指数。
数据范围：


解题思路：
#include &lt;iostream&gt;#include &lt;algorithm&gt;using namespace std;void divide(int x){    for (int i = 2; i &lt;= x / i; i ++ )        if (x % i == 0)        {            int s = 0;            while (x % i == 0) x /= i, s ++ ;            cout &lt;&lt; i &lt;&lt; ' ' &lt;&lt; s &lt;&lt; endl;        }    if (x &gt; 1) cout &lt;&lt; x &lt;&lt; ' ' &lt;&lt; 1 &lt;&lt; endl;    cout &lt;&lt; endl;}int main(){    int count;    cin &gt;&gt; count;    while(count--){        int n;        cin &gt;&gt; n;        divide(n);    }    return 0;}

3. 质数筛选参考：质数其实没有那么多。100 万以内，大概有 8 万个质数。
方法 1：这种筛选方法的时间复杂度为：
#include &lt;iostream&gt;#include &lt;algorithm&gt;using namespace std;const int N = 1000010;int primes[N] , cnt ;bool st[N];void get_primes(int n){    for(int i = 2 ; i &lt;= n ; i++ ){        // 如果这个数已经被筛过了，那么留下的数是一个质数，直接就存到 primes 数组中        if(!st[i]){						// 把这个质数存进 primes 数组中            primes[ cnt ++ ] = i ;        }        // j 从 2i 开始循环，查看i的倍数，给它赋值为true，标记他不是一个质数        for(int j = i + i ; j &lt;= n ; j += i) st[j] = true;    }}int main(){    int n;    cin &gt;&gt; n ;    get_primes(n);    cout &lt;&lt; cnt &lt;&lt; endl;    return 0;}

方法 2：埃氏筛法质数定理：1 ～ n 中，有 个质数。
这个方法中的时间复杂度约为  ，基本上和 O(n) 复杂度是一个级别的。
这个算法也称为 埃氏筛法。
#include &lt;iostream&gt;#include &lt;algorithm&gt;using namespace std;const int N = 1000010;int primes[N] , cnt ;bool st[N];void get_primes(int n){    for(int i = 2 ; i &lt;= n ; i++ ){        // 确认了这个数是一个质数了        if(!st[i]){						// 把这个质数存进 primes 数组中            primes[cnt++] = i;            // 只需要把质数的倍数筛掉，就可以了            for(int j = i+i ; j &lt;= n ; j += i) st[j] = true;        }    }}int main(){    int n;    cin &gt;&gt; n;    get_primes(n);    cout &lt;&lt; cnt &lt;&lt; endl;    return 0;}

方法 3：线性筛法n 只会被最小质因子筛掉
每一个数只会被最小质因子筛一次，所以是线性的。
注：下面两个代码的 primes 数组声明方式不一样。一个用普通数组，一个用 vector。供参考
// 注释版本#include &lt;iostream&gt;#include &lt;algorithm&gt;using namespace std;const int N = 1000010;int primes[N] , cnt ;bool st[N];void get_primes(int n){    for(int i = 2 ; i &lt;= n ; i++ ){        // 如果这个数没被筛掉，那么这个数为质数        if(!st[i]) primes[cnt ++] = i;        // 从小到大枚举所有的质数        for(int j = 0 ; primes[j] &lt;= n / i ; j ++){            // 把当前质数和i的乘积筛掉            st[ primes[j] * i] = true;      // 只用最小质因子来筛选            if( i % primes[j] == 0) break;  // 当这句话发生的时候，说明primes[j]一定是i的最小质因子            // 1. i % primes[j] == 0，此时，primes[j]一定是i的最小质因子，即 primes[j] 一定是 primes[j] * i 的最小质因子            // 2. i % primes[j] != 0，primes[j] 一定小于i的所有质因子，即 primes[j] 一定是 primes[j] * i 的最小质因子        }    }}int main(){    int n;    cin &gt;&gt; n;    get_primes(n);    cout &lt;&lt; cnt &lt;&lt; endl;    return 0;}

#include &lt;bits/stdc++.h&gt;using namespace std;typedef long long LL;typedef pair&lt;int, int&gt; PII;const int N = 1000010;int cnt;bool st[N];vector&lt;int&gt; primes;void get_primes(int n) {    for (int i = 2; i &lt;= n; i++) {        if (!st[i])            primes.push_back(i);        for (int j = 0; primes[j] &lt;= n / i; j++) {            st[primes[j] * i] = true;            if (i % primes[j] == 0)                break;        }    }}int main() {    int n;    cin &gt;&gt; n;    get_primes(n);    cout &lt;&lt; primes.size() &lt;&lt; endl;}
